def main():
    if len(sys.argv) < 3:
        print("Usage: python -m spl <policy.spl> <request.json>", file=sys.stderr)
        sys.exit(1)

    policy_path = Path(sys.argv[1])
    request_path = Path(sys.argv[2])

    policy_src = policy_path.read_text().strip()
    ast = parse(policy_src)

    req = json.loads(request_path.read_text())

    env = {
        "vars": {
            "allowed_recipients": ["niece@example.com", "mom@example.com"],
            "now": "2025-10-01T00:00:00Z",
        },
        "now": "2025-10-01T00:00:00Z",
        "per_day_count": lambda _a, _d: 0,
        "crypto": {
            "dpop_ok": lambda: True,
            "merkle_ok": lambda _t: True,
            "vrf_ok": lambda _d, _a: True,
            "thresh_ok": lambda: True,
        },
    }

    result = verify(ast, req, env)
    print("ALLOW" if result["allow"] else "DENY")

def sha256(data: bytes) -> bytes:
    """SHA-256 hash of data."""
    return hashlib.sha256(data).digest()

def sha256_hex(data: bytes) -> str:
    """SHA-256 hash of data as hex string."""
    return hashlib.sha256(data).hexdigest()

def verify_merkle_proof(
    leaf_data: str,
    proof: list[dict[str, str]],
    root_hex: str,
) -> bool:
    """Verify a Merkle proof for leaf_data against root_hex.

    Args:
        leaf_data: The leaf value (will be SHA-256 hashed)
        proof: List of {"hash": hex, "position": "left"|"right"}
        root_hex: Expected root hash in hex
    """
    try:
        current = sha256(leaf_data.encode("utf-8"))

        for step in proof:
            sibling = bytes.fromhex(step["hash"])
            if step["position"] == "right":
                current = sha256(current + sibling)
            else:
                current = sha256(sibling + current)

        return current.hex() == root_hex
    except Exception:
        return False

def hash_tuple(values: list[Any]) -> str:
    """Hash a tuple by JSON-serializing then SHA-256."""
    serialized = json.dumps(values, separators=(",", ":"))
    return sha256_hex(serialized.encode("utf-8"))

def _eval(node: Any, ctx: dict, st: _EvalState) -> Any:
    st.gas -= 1
    if st.gas < 0:
        raise GasExhausted("gas budget exceeded")
    st.depth += 1
    if st.depth > MAX_DEPTH:
        st.depth -= 1
        raise DepthExceeded("max nesting depth exceeded")
    try:
        return _eval_inner(node, ctx, st)
    finally:
        st.depth -= 1

def _eval_inner(node: Any, ctx: dict, st: _EvalState) -> Any:
    if not isinstance(node, list):
        return _resolve_symbol(node, ctx)
    if len(node) == 0:
        return None
    op = node[0]
    args = node[1:]

    # --- Logical ---
    if op == "and":
        for a in args:
            if not _truthy(_eval(a, ctx, st)):
                return False
        return True

    if op == "or":
        for a in args:
            if _truthy(_eval(a, ctx, st)):
                return True
        return False

    if op == "not":
        return not _truthy(_eval(args[0], ctx, st))

    # --- Comparison ---
    if op == "=":
        return _eval(args[0], ctx, st) == _eval(args[1], ctx, st)

    if op in ("<=", "<", ">=", ">"):
        a = _to_float(_eval(args[0], ctx, st))
        b = _to_float(_eval(args[1], ctx, st))
        if op == "<=":
            return a <= b
        if op == "<":
            return a < b
        if op == ">=":
            return a >= b
        return a > b

    # --- Sets ---
    if op in ("member", "in"):
        val = _eval(args[0], ctx, st)
        lst = _eval(args[1], ctx, st)
        if isinstance(lst, list):
            return val in lst
        return False

    if op == "subset?":
        a = _eval(args[0], ctx, st)
        b = _eval(args[1], ctx, st)
        if not isinstance(a, list) or not isinstance(b, list):
            return False
        return all(item in b for item in a)

    # --- Time ---
    if op == "before":
        a = _eval(args[0], ctx, st)
        b = _eval(args[1], ctx, st)
        return str(a) < str(b)

    # --- Accessors ---
    if op == "get":
        obj = _resolve_symbol(args[0], ctx)
        key = _eval(args[1], ctx, st)
        if isinstance(obj, dict) and isinstance(key, str):
            return obj.get(key)
        return None

    if op == "tuple":
        return [_eval(a, ctx, st) for a in args]

    # --- Counter ---
    if op == "per-day-count":
        action = _eval(args[0], ctx, st)
        day = _eval(args[1], ctx, st)
        fn = ctx.get("per_day_count")
        if fn:
            return fn(str(action), str(day))
        return 0

    # --- Crypto predicates ---
    crypto = ctx.get("crypto", {})

    if op == "dpop_ok?":
        fn = crypto.get("dpop_ok") if isinstance(crypto, dict) else getattr(crypto, "dpop_ok", None)
        return fn() if fn else False

    if op == "merkle_ok?":
        evaluated = [_eval(a, ctx, st) for a in args]
        fn = crypto.get("merkle_ok") if isinstance(crypto, dict) else getattr(crypto, "merkle_ok", None)
        return fn(evaluated) if fn else False

    if op == "vrf_ok?":
        day = _eval(args[0], ctx, st)
        amount = _eval(args[1], ctx, st)
        fn = crypto.get("vrf_ok") if isinstance(crypto, dict) else getattr(crypto, "vrf_ok", None)
        return fn(str(day), _to_float(amount)) if fn else False

    # thresh_ok? — Threshold co-signature verification.
    # Expected protocol: k-of-n co-signatures where the verifier checks each
    # signature against its corresponding public key and confirms count >= threshold.
    # Not implemented in v0.1 — remains an interface stub. Provide your own
    # implementation via the crypto callbacks when integrating.
    if op == "thresh_ok?":
        fn = crypto.get("thresh_ok") if isinstance(crypto, dict) else getattr(crypto, "thresh_ok", None)
        return fn() if fn else False

    raise SPLError(f"Unknown op: {op}")

def _resolve_symbol(x: Any, ctx: dict) -> Any:
    if isinstance(x, str):
        if x == "#t":
            return True
        if x == "#f":
            return False
        if x == "req":
            return ctx.get("req", {})
        if x == "now":
            v = ctx.get("vars", {})
            if isinstance(v, dict) and "now" in v:
                return v["now"]
            if ctx.get("strict"):
                raise SPLError(f"Unresolved symbol: {x}")
            return x
        v = ctx.get("vars", {})
        if isinstance(v, dict) and x in v:
            return v[x]
        if ctx.get("strict"):
            raise SPLError(f"Unresolved symbol: {x}")
    return x

def _truthy(v: Any) -> bool:
    if v is None:
        return False
    if isinstance(v, bool):
        return v
    if isinstance(v, (int, float)):
        return v != 0
    return True

def _to_float(x: Any) -> float:
    if isinstance(x, (int, float)):
        return float(x)
    try:
        return float(x)
    except (TypeError, ValueError):
        return 0.0

def __init__(self, max_gas: int):
    self.gas = max_gas
    self.depth = 0

def tokenize(src: str) -> list[str]:
    tokens: list[str] = []
    buf = ""
    in_str = False
    for ch in src:
        if in_str:
            buf += ch
            if ch == '"':
                in_str = False
                tokens.append(buf)
                buf = ""
            continue
        if ch == '"':
            if buf.strip():
                tokens.extend(buf.strip().split())
            buf = '"'
            in_str = True
            continue
        if ch in ("(", ")"):
            if buf.strip():
                tokens.extend(buf.strip().split())
            tokens.append(ch)
            buf = ""
            continue
        buf += ch
    if buf.strip():
        tokens.extend(buf.strip().split())
    return tokens

def _atom(tok: str) -> AST:
    if tok == "#t":
        return True
    if tok == "#f":
        return False
    # Try number
    try:
        if "." in tok:
            return float(tok)
        return int(tok) if tok.lstrip("-").isdigit() else float(tok)
    except (ValueError, AttributeError):
        pass
    # Quoted string
    if tok.startswith('"') and tok.endswith('"'):
        return tok[1:-1].replace('\\"', '"')
    # Symbol (returned as string)
    return tok

def parse(src: str) -> AST:
    """Parse an SPL S-expression string into an AST."""
    if len(src.encode("utf-8")) > MAX_POLICY_BYTES:
        raise SyntaxError(f"policy exceeds maximum size of {MAX_POLICY_BYTES} bytes")
    tokens = tokenize(src.strip())
    if not tokens:
        raise SyntaxError("unexpected EOF")
    pos = [0]  # mutable index

    def _parse() -> AST:
        if pos[0] >= len(tokens):
            raise SyntaxError("unexpected EOF")
        tok = tokens[pos[0]]
        pos[0] += 1
        if tok == "(":
            arr: list[AST] = []
            while True:
                if pos[0] >= len(tokens):
                    raise SyntaxError("unterminated (")
                if tokens[pos[0]] == ")":
                    pos[0] += 1
                    break
                arr.append(_parse())
            return arr
        if tok == ")":
            raise SyntaxError("unexpected )")
        return _atom(tok)

    result = _parse()
    if pos[0] != len(tokens):
        raise SyntaxError("extra tokens")
    return result

def _parse() -> AST:
    if pos[0] >= len(tokens):
        raise SyntaxError("unexpected EOF")
    tok = tokens[pos[0]]
    pos[0] += 1
    if tok == "(":
        arr: list[AST] = []
        while True:
            if pos[0] >= len(tokens):
                raise SyntaxError("unterminated (")
            if tokens[pos[0]] == ")":
                pos[0] += 1
                break
            arr.append(_parse())
        return arr
    if tok == ")":
        raise SyntaxError("unexpected )")
    return _atom(tok)

def verify_token(
    token: dict | str,
    req: dict[str, Any],
    *,
    vars: Optional[dict[str, Any]] = None,
    per_day_count: Any = None,
    crypto: Optional[dict] = None,
    now: Optional[str] = None,
    presentation_signature: Optional[str] = None,
) -> dict[str, Any]:
    """Verify a token's signature and evaluate its policy.

    Args:
        token: Token dict or JSON string
        req: Request dict
        vars: Host variables (e.g. allowed_recipients)
        per_day_count: Callback(action, day) -> int
        crypto: Dict of crypto callbacks (dpop_ok, merkle_ok, vrf_ok, thresh_ok)
        now: Current time as ISO 8601 string (defaults to now)

    Returns:
        {"allow": bool, "sealed": bool, "error": str | None}
    """
    if isinstance(token, str):
        token = json.loads(token)

    t = token
    sealed = t.get("sealed", False)

    # Check expiration
    if t.get("expires"):
        exp = datetime.fromisoformat(t["expires"])
        current = datetime.fromisoformat(now) if now else datetime.now(timezone.utc)
        if hasattr(current, 'tzinfo') and current.tzinfo is None:
            current = current.replace(tzinfo=timezone.utc)
        if hasattr(exp, 'tzinfo') and exp.tzinfo is None:
            exp = exp.replace(tzinfo=timezone.utc)
        if current > exp:
            return {"allow": False, "sealed": sealed, "error": "token expired"}

    # Verify signature over full token envelope
    payload = signing_payload(
        t["policy"],
        t.get("merkle_root"),
        t.get("hash_chain_commitment"),
        sealed,
        t.get("expires"),
    )
    if not verify_ed25519(payload, t["signature"], t["public_key"]):
        return {"allow": False, "sealed": sealed, "error": "invalid signature"}

    # PoP binding: if token has pop_key, require and verify presentation signature
    if t.get("pop_key"):
        if not presentation_signature:
            return {"allow": False, "sealed": sealed, "error": "PoP binding requires presentation signature"}
        pop_payload = sha256(payload)
        if not verify_ed25519(pop_payload, presentation_signature, t["pop_key"]):
            return {"allow": False, "sealed": sealed, "error": "invalid presentation signature"}

    # Parse and evaluate
    ast = parse(t["policy"])

    ctx_vars = dict(vars or {})
    if now:
        ctx_vars["now"] = now

    ctx = {
        "req": req,
        "vars": ctx_vars,
        "now": now or datetime.now(timezone.utc).isoformat(),
        "per_day_count": per_day_count or (lambda _a, _d: 0),
        "crypto": crypto or {},
    }

    result = eval_policy(ast, ctx)
    allow = bool(result) if result is not None else False

    return {"allow": allow, "sealed": sealed}

def verify(policy_ast: Any, req: dict, env: Any) -> dict:
    """Evaluate an SPL policy AST against a request.

    Args:
        policy_ast: Parsed SPL AST (from spl.parse)
        req: Request dict (e.g. {"actor_pub": "K_ai", "action": "payments.create", ...})
        env: Environment — either an Env dataclass or a dict with keys:
             vars, now, per_day_count, crypto, max_gas/maxGas

    Returns:
        {"allow": bool, "obligations": list}
    """
    if isinstance(env, dict):
        ctx = {
            "req": req,
            "vars": env.get("vars", {}),
            "now": env.get("now", ""),
            "per_day_count": env.get("per_day_count", lambda _a, _d: 0),
            "crypto": env.get("crypto", {}),
            "maxGas": env.get("maxGas") or env.get("max_gas"),
        }
    else:
        # Env dataclass
        ctx = {
            "req": req,
            "vars": env.vars if hasattr(env, "vars") else {},
            "now": env.now if hasattr(env, "now") else "",
            "per_day_count": env.per_day_count if hasattr(env, "per_day_count") else (lambda _a, _d: 0),
            "crypto": env.crypto if hasattr(env, "crypto") else {},
            "maxGas": env.max_gas if hasattr(env, "max_gas") else None,
        }
    sealed = False
    if isinstance(env, dict):
        sealed = env.get("sealed", False)
    elif hasattr(env, "sealed"):
        sealed = env.sealed

    if sealed:
        return {"allow": False, "sealed": True, "error": "token is sealed and cannot be attenuated"}

    result = eval_policy(policy_ast, ctx)
    allow = bool(result) if result is not None else False
    return {"allow": allow, "sealed": False}
